						},
						"type": "block"
					},
					{
						"item": "input_KtlHhgqi",
						"position": {
							"h": 102,
							"w": 720,
							"x": 720,
							"y": 0
						},
						"type": "input"
					},
					{
						"item": "viz_lUxfc0dH",
						"position": {
							"h": 953,
							"w": 720,
							"x": 720,
							"y": 102
						},
						"type": "block"
					},
					{
						"item": "viz_zKOtw4RX",
						"position": {
							"h": 400,
							"w": 1440,
							"x": 0,
							"y": 1055
						},
						"type": "block"
					}
				],
				"type": "grid"
			}
		},
		"options": {
			"submitButton": false
		},
		"tabs": {
			"items": [
				{
					"label": "New tab",
					"layoutId": "layout_1"
				}
			]
		}
	},
	"applicationProperties": {
		"hideEdit": false,
		"hideExport": false
	}
}
